While testing a sender instance we noticed that we get segfaults when `stream.async_send_heap` is called many times in succession. The segfaults are sporadic but when running through Valgrind we see the same invalid memory access on every run. Below is a minimum failing example:

```
#include <iostream>
#include <utility>
#include <vector>
#include <thread>
#include <chrono>
#include <boost/asio.hpp>
#include <spead2/common_endian.h>
#include <spead2/common_thread_pool.h>
#include <spead2/common_defines.h>
#include <spead2/common_flavour.h>
#include <spead2/send_heap.h>
#include <spead2/send_udp.h>
#include <spead2/send_stream.h>

#define HOST "127.0.0.1"
#define PORT "8888"
#define NBEAMS 1
#define NHEAPS 100

using boost::asio::ip::udp;

int main()
{
  spead2::thread_pool tp;
  udp::resolver resolver(tp.get_io_service());
  udp::resolver::query query(HOST, PORT);
  auto it = resolver.resolve(query);
  auto config = spead2::send::stream_config(9000, 1e7, 65536, 100);
  spead2::send::udp_stream stream(tp.get_io_service(), *it, config);
  spead2::flavour f(spead2::maximum_version, 64, 48, spead2::BUG_COMPAT_PYSPEAD_0_5_2);

  bool first_heap = true;

  spead2::descriptor timestamp_desc;
  timestamp_desc.id = 0x1600;
  timestamp_desc.name = "timestamp";
  timestamp_desc.description = "sampler clock ticks since epoch";
  timestamp_desc.format.emplace_back('u', 32);

  std::uint32_t timestamp = 0;
  std::uint32_t timestamp_r = spead2::htobe(std::uint32_t(timestamp));

  for (std::size_t heap=0; heap < NHEAPS; ++heap)
    {
      spead2::send::heap h(f);

      if (first_heap)
	{
	  h.add_descriptor(timestamp_desc);
	  first_heap = false;
	}

      //timestamp
      h.add_item(0x1600, &(timestamp_r), sizeof(timestamp), true);

      stream.async_send_heap(h, [timestamp]
			     (const boost::system::error_code &ec,
			      spead2::item_pointer_t bytes_transferred)
			     {
			       if (ec)
				 std::cerr << ec.message() << '\n';
			       else
				 std::cout << "Sent " << bytes_transferred
					   << " bytes in heap\n";
			     });
      //std::this_thread::sleep_for(std::chrono::milliseconds(100));
      timestamp_r = spead2::htobe(std::uint32_t(++timestamp));
    }
  stream.flush();
  std::this_thread::sleep_for(std::chrono::seconds(1));
  spead2::send::heap end(f);
  end.add_end();
  stream.async_send_heap(end, []
			 (const boost::system::error_code &ec,
			  spead2::item_pointer_t bytes_transferred) {});
  stream.flush();
  return 0;
}
```

Note that uncommenting the line `std::this_thread::sleep_for(std::chrono::milliseconds(100));` stops the segfaults. We have played around with various sleep times and we see segfaults with sleeps less than ~10 milliseconds. It strikes me that this is likely a race condition somewhere. The first 100 lines of the Valgrind output are shown below:

